(self.webpackChunkvuepress_blog=self.webpackChunkvuepress_blog||[]).push([[4778],{958:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>e});const e={key:"v-7d3b6358",path:"/pages/vue/usefulTips/",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:3,title:"问题 1:vue data 里初始值为 undefined 的值，不会做响应式处理",slug:"问题-1-vue-data-里初始值为-undefined-的值-不会做响应式处理",children:[]},{level:3,title:"问题 2: null 值不会触发 prop 的 default 逻辑",slug:"问题-2-null-值不会触发-prop-的-default-逻辑",children:[]},{level:3,title:"多文件单文件组件",slug:"多文件单文件组件",children:[]},{level:3,title:"处理错误（和警告）的更好方法",slug:"处理错误-和警告-的更好方法",children:[]},{level:3,title:"妙用 hook 事件",slug:"妙用-hook-事件",children:[]}],filePathRelative:"pages/vue/usefulTips/README.md",git:{updatedTime:1655601466e3,contributors:[{name:"guilin.li",email:"1344714332@qq.com",commits:3}]}}},420:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>p});const e=(0,a(6252).uE)('<h3 id="问题-1-vue-data-里初始值为-undefined-的值-不会做响应式处理"><a class="header-anchor" href="#问题-1-vue-data-里初始值为-undefined-的值-不会做响应式处理">#</a> 问题 1:vue data 里初始值为 undefined 的值，不会做响应式处理</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">class</span> <span class="token class-name">AddAddress</span> <span class="token keyword">extends</span> <span class="token class-name">Vue</span> <span class="token punctuation">{</span>\n  <span class="token keyword">private</span> address<span class="token operator">:</span> Object<span class="token punctuation">;</span> <span class="token comment">// 没赋值的话默认为undefined，undefined不会做响应式处理，后续的变更不会触发页面的更新</span>\n  <span class="token keyword">private</span> address<span class="token operator">:</span> Object <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span> <span class="token comment">// 需要响应式的话需要赋一个初始值，比如null</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="问题-2-null-值不会触发-prop-的-default-逻辑"><a class="header-anchor" href="#问题-2-null-值不会触发-prop-的-default-逻辑">#</a> 问题 2: null 值不会触发 prop 的 default 逻辑</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">class</span> <span class="token class-name">AddAddress</span> <span class="token keyword">extends</span> <span class="token class-name">Vue</span> <span class="token punctuation">{</span>\n  <span class="token keyword">private</span> address<span class="token operator">:</span> Object<span class="token punctuation">;</span> <span class="token comment">// 没赋值的话默认为undefined，undefined不会做响应式处理，后续的变更不会触发页面的更新</span>\n  <span class="token keyword">private</span> address<span class="token operator">:</span> Object <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span> <span class="token comment">// 需要响应式的话需要赋一个初始值，比如null</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="多文件单文件组件"><a class="header-anchor" href="#多文件单文件组件">#</a> 多文件单文件组件</h3><p>这是**SFC(单文件组件)**的一点已知功能。 可以像常规 HTML 文件一样导入文件：</p><div class="language-Vue ext-Vue line-numbers-mode"><pre class="language-Vue"><code>&lt;template src=&quot;./template.html&quot;&gt;&lt;/template&gt;\n&lt;script src=&quot;./script.js&quot;&gt;&lt;/script&gt;\n&lt;style scoped src=&quot;./styles.css&quot;&gt;&lt;/style&gt;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果你需要分享样式、文件或其他任何东西，这可能会非常方便。</p><h3 id="处理错误-和警告-的更好方法"><a class="header-anchor" href="#处理错误-和警告-的更好方法">#</a> 处理错误（和警告）的更好方法</h3><p>我们可以为 Vue 中的错误和警告提供一个自定义处理程序。</p><div class="language-vue ext-vue line-numbers-mode"><pre class="language-vue"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">ts</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">\n<span class="token keyword">const</span> app <span class="token operator">=</span> <span class="token function">createApp</span><span class="token punctuation">(</span>App<span class="token punctuation">)</span><span class="token punctuation">;</span>\napp<span class="token punctuation">.</span>config<span class="token punctuation">.</span><span class="token function-variable function">errorHandler</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">err</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n  <span class="token function">alert</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span><span class="token punctuation">;</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><div class="language-vue ext-vue line-numbers-mode"><pre class="language-vue"><code>\nVue.config.errorHandler = (err) =&gt; {\n  alert(err);\n};\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>像 Bugsnag 和 Rollbar 这样的错误跟踪服务，可以钩住这些处理程序来记录错误，但你也可以用它们来更优雅地处理错误，以获得更好的用户体验。 例如，如果一个错误未被处理，应用程序不会直接崩溃，你可以显示一个完整的错误屏幕，让用户刷新或尝试其他东西。 在 Vue3 中，错误处理程序只能处理  template  和  watcher  错误，但是  Vue2 的错误处理程序可以捕获几乎所有错误。这两个版本中的警告处理程序只在开发阶段有效。</p><h3 id="妙用-hook-事件"><a class="header-anchor" href="#妙用-hook-事件">#</a> 妙用 hook 事件</h3><p>如果想监听子组件的生命周期时，可以像下面例子中这么做：</p><div class="language-vue ext-vue line-numbers-mode"><pre class="language-vue"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>child</span> <span class="token attr-name"><span class="token namespace">@hook:</span>mounted</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>removeLoading<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>\n复制代码\n这样的写法可以用于处理加载第三方的初始化过程稍漫长的子组件时，我们可以加loading动画，等到子组件加载完毕，到了mounted生命周期时，把loading动画移除。\n初次之外hook还有一个常用的写法，在一个需要轮询更新数据的组件上，我们通常在created里开启定时器，然后在beforeDestroy上清除定时器。而通过hook,开启和销毁定时器的逻辑我们都可以在created里实现：\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">\n  <span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>\n    <span class="token function">created</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n      <span class="token keyword">const</span> timer <span class="token operator">=</span> <span class="token function">setInterval</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n        <span class="token comment">// 更新逻辑</span>\n      <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token number">1000</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n      <span class="token comment">// 通过$once和hook监听实例自身的beforeDestroy，触发该生命周期时清除定时器</span>\n      <span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function">$once</span><span class="token punctuation">(</span><span class="token string">&quot;hook:beforeDestroy&quot;</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n        <span class="token function">clearInterval</span><span class="token punctuation">(</span>timer<span class="token punctuation">)</span><span class="token punctuation">;</span>\n      <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token punctuation">}</span><span class="token punctuation">;</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><p>const broadcast = function(componentName, eventName, ...params) { let children = this.$children; children.forEach(child =&gt; { let name = child.$options.name; if (name === componentName) { child.$emit(eventName, ...params); } else { broadcast.call(child, componentName, eventName, ...params); } }); };</p><p>const dispatch = function (componentName, eventName, ...params) { let parent = this.$parent || this.$root; let name = parent.$options.name; while (parent &amp;&amp; componentName !== name) { parent = parent.$parent; if (parent) { name = parent.$options.name; } } if (parent) { parent.$emit(eventName, ...params); } };</p><p>export default { methods: { dispatch(componentName, eventName, ...params) { dispatch.call(this, componentName, eventName, ...params); }, broadcast(componentName, eventName, ...params) { broadcast.call(this, componentName, eventName, ...params); } } };</p>',19),p={render:function(n,s){return e}}}}]);